import React from 'react';

export default function ExpenseCard({ expense, onEdit, onDelete, deleting }) {
  const formatCurrency = (v) => {
    try {
      return new Intl.NumberFormat('en-IN', {
        style: 'currency',
        currency: 'INR',
      }).format(v);
    } catch (e) {
      return `₹${Number(v).toFixed(2)}`;
    }
  };

  return (
    <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 items-center p-4 rounded-xl bg-white/5 border border-white/10 shadow-sm hover:bg-white/10 transition overflow-hidden">

      {/* CATEGORY */}
      <div className="min-w-0">
        <p className="font-medium text-white truncate">
          {expense.category}
        </p>

        <p className="text-sm text-gray-400 sm:hidden mt-1">
          {new Date(expense.date).toLocaleDateString()}
        </p>
      </div>

      {/* CATEGORY (desktop) */}
      <div className="hidden sm:block text-sm text-gray-400 truncate">
        {expense.category}
      </div>

      {/* DATE */}
      <div className="hidden sm:block text-sm text-gray-400 whitespace-nowrap">
        {new Date(expense.date).toLocaleDateString()}
      </div>

      {/* ACTIONS */}
      <div className="flex items-center justify-end gap-3 flex-wrap sm:flex-nowrap">

        <span className="font-semibold text-red-400 whitespace-nowrap">
          {expense.type === 'expense' ? '-' : '+'}
          {formatCurrency(expense.amount)}
        </span>

        <button
          onClick={() => onEdit(expense)}
          className="px-3 py-1 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition whitespace-nowrap"
        >
          Edit
        </button>

        <button
          onClick={() => onDelete(expense._id)}
          disabled={deleting}
          className="px-3 py-1 bg-red-500 text-white rounded-lg hover:bg-red-600 transition disabled:opacity-50 whitespace-nowrap"
        >
          {deleting ? 'Deleting...' : 'Delete'}
        </button>

      </div>
    </div>
  );
}
